// Fan out QBO Query API response into one item per overdue invoice.
// Empty result (no overdue invoices today) is normal — returns [] cleanly.
try {
  const resp = $input.first().json;
  const invoices = resp?.QueryResponse?.Invoice ?? [];
  if (!Array.isArray(invoices)) {
    throw new Error('QueryResponse.Invoice is present but not an array');
  }
  return invoices.map(inv => ({ json: inv }));
} catch (err) {
  throw new Error('Extract invoices failed: ' + err.message);
}

// Merge QBO customer payload + Supabase tag state into a single working object.
// Untagged customers (no row in customer_tags) default to relationship_tag='standard'.
// contact_email_hash is an 8-char deterministic prefix used by the audit log; raw email
// is kept on the object for the Gmail send only but is NEVER persisted to Supabase.
function hash8(str) {
  if (!str) return null;
  let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
  for (let i = 0, ch; i < str.length; i++) {
    ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507) ^ Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507) ^ Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  const v = 4294967296 * (2097151 & h2) + (h1 >>> 0);
  return v.toString(16).padStart(14, '0').slice(0, 8);
}

try {
  const customer = $('Fetch Customer').first().json.Customer;
  if (!customer || !customer.Id) {
    throw new Error('QBO Customer payload missing Id');
  }
  const tagRow = $input.first().json;
  const invoice = $('Split In Batches').first().json;
  const hasTagRow = tagRow && tagRow.relationship_tag !== undefined;
  const email = customer.PrimaryEmailAddr?.Address ?? null;

  return [{
    json: {
      invoice: invoice,
      customer_id: String(customer.Id),
      customer_name: customer.DisplayName ?? tagRow?.contact_name ?? 'unknown',
      customer_email: email,
      contact_email_hash: email ? hash8(email.toLowerCase().trim()) : null,
      relationship_tag: hasTagRow ? tagRow.relationship_tag : 'standard',
      pause_all: hasTagRow ? (tagRow.pause_all === true) : false
    }
  }];
} catch (err) {
  throw new Error('Apply defaults failed: ' + err.message);
}

// Compute days_overdue and decide action based on (days_overdue, relationship_tag).
// today_iso comes from the Set Today node (single source of truth for the run).
// action_taken in {NONE, REMINDER_1..4, ESCALATED}; sequence_step in {1..4, null}.
try {
  const todayIso = $('Set Today').first().json.today_iso;
  if (!todayIso || !/^\d{4}-\d{2}-\d{2}$/.test(todayIso)) {
    throw new Error('Invalid today_iso from Set Today: ' + todayIso);
  }
  const item = $input.first().json;
  const dueDate = item.invoice?.DueDate;
  if (!dueDate) {
    throw new Error('Invoice missing DueDate');
  }
  const todayMs = Date.UTC(
    parseInt(todayIso.slice(0, 4), 10),
    parseInt(todayIso.slice(5, 7), 10) - 1,
    parseInt(todayIso.slice(8, 10), 10)
  );
  const dueMs = Date.UTC(
    parseInt(dueDate.slice(0, 4), 10),
    parseInt(dueDate.slice(5, 7), 10) - 1,
    parseInt(dueDate.slice(8, 10), 10)
  );
  const daysOverdue = Math.floor((todayMs - dueMs) / 86400000);

  const tag = item.relationship_tag || 'standard';
  let action = 'NONE';
  let step = null;

  if (tag === 'standard' || tag === 'new') {
    if (daysOverdue === 1)       { action = 'REMINDER_1'; step = 1; }
    else if (daysOverdue === 7)  { action = 'REMINDER_2'; step = 2; }
    else if (daysOverdue === 21) { action = 'REMINDER_3'; step = 3; }
    else if (daysOverdue === 45) { action = 'REMINDER_4'; step = 4; }
    else if (daysOverdue >= 60)  { action = 'ESCALATED';  step = null; }
  } else if (tag === 'long-term-trusted') {
    if (daysOverdue === 14)      { action = 'REMINDER_1'; step = 1; }
    else if (daysOverdue === 35) { action = 'REMINDER_2'; step = 2; }
    else if (daysOverdue >= 60)  { action = 'ESCALATED';  step = null; }
  }

  return [{ json: { ...item, days_overdue: daysOverdue, action_taken: action, sequence_step: step } }];
} catch (err) {
  throw new Error('Compute action failed: ' + err.message);
}

// Build the email subject + body for the reminder. Templates are inline as a static
// map keyed by action_taken. v2 path: lift TEMPLATES into a Set node or a Supabase
// templates table so a non-technical user can edit copy without opening a Code node.
try {
  const ctx = $('Compute Action').first().json;
  const owner = 'Tabitha';
  const action = ctx.action_taken;
  const balance = ctx.invoice?.Balance ?? 0;
  const balanceFormatted = '$' + Number(balance).toFixed(2);
  const invoiceNumber = ctx.invoice?.DocNumber ?? ctx.invoice?.Id;
  const days = ctx.days_overdue;
  const name = ctx.customer_name;

  const TEMPLATES = {
    REMINDER_1: {
      subject: 'Quick note about invoice ' + invoiceNumber,
      body:
        'Hi ' + name + ',\n\n' +
        'Just a quick note in case this was missed: your balance of ' + balanceFormatted +
        ' on invoice #' + invoiceNumber + ' is now ' + days + ' day(s) past due.\n\n' +
        'If payment has already been sent, please ignore this message. Otherwise, please ' +
        'let me know if there is anything I can help with.\n\n' +
        'Thanks,\n' + owner
    },
    REMINDER_2: {
      subject: 'Following up on invoice ' + invoiceNumber,
      body:
        'Hi ' + name + ',\n\n' +
        'Following up on invoice #' + invoiceNumber + '. The balance of ' + balanceFormatted +
        ' is now ' + days + ' days past due. Could you confirm when payment is on its way?\n\n' +
        'Happy to help if anything is holding things up on your end.\n\n' +
        'Thanks,\n' + owner
    },
    REMINDER_3: {
      subject: 'Invoice ' + invoiceNumber + ' is significantly past due',
      body:
        'Hi ' + name + ',\n\n' +
        'Invoice #' + invoiceNumber + ' for ' + balanceFormatted + ' is now ' + days +
        ' days past due. Please could you confirm payment timing, or get in touch if ' +
        'there is an issue with the invoice itself.\n\n' +
        'Thanks,\n' + owner
    },
    REMINDER_4: {
      subject: 'Invoice ' + invoiceNumber + ' — final reminder before escalation',
      body:
        'Hi ' + name + ',\n\n' +
        'This is a final reminder on invoice #' + invoiceNumber + ' for ' + balanceFormatted +
        ', now ' + days + ' days past due. If we do not hear back from you within the next ' +
        'few days, we will need to discuss this directly.\n\n' +
        'Please let me know how you would like to proceed.\n\n' +
        'Thanks,\n' + owner
    }
  };

  const tpl = TEMPLATES[action];
  if (!tpl) {
    throw new Error('No template defined for action: ' + action);
  }

  return [{ json: { ...ctx, email_subject: tpl.subject, email_body: tpl.body } }];
} catch (err) {
  throw new Error('Build email template failed: ' + err.message);
}

